  1→import supabase from "./supabase.js";
  2→import { createMediaResponsePayload } from "../utils/mediaVariants.js";
  3→
  4→const NOTIFICATION_LIMIT_MIN = 1;
  5→const NOTIFICATION_LIMIT_MAX = 20;
  6→const NOTIFICATION_DEFAULT_LIMIT = 5;
  7→
  8→const NOTIFICATION_JOURNAL_SELECT = `
  9→    id,
 10→    sender_id,
 11→    receiver_id,
 12→    journal_id,
 13→    repost_journal_id,
 14→    type,
 15→    reaction_type,
 16→    read,
 17→    created_at,
 18→    journals!journal_id(
 19→        title,
 20→        preview_text,
 21→        thumbnail_url,
 22→        created_at,
 23→        users(id, name, image_url, badge)
 24→    ),
 25→    users!sender_id(id, name, image_url, badge)
 26→`;
 27→
 28→const NOTIFICATION_OPINION_SELECT = `
 29→    id,
 30→    sender_id,
 31→    receiver_id,
 32→    opinion_id,
 33→    read,
 34→    created_at,
 35→    opinions!opinion_id(id, opinion, user_id, created_at),
 36→    users!sender_id(id, name, image_url, badge)
 37→`;
