162→export const getCountNotificationsService = async (userId) => {
163→    const { data, error } = await supabase.rpc('get_unread_notification_count', {
164→        p_user_id: userId,
165→    });
166→
167→    if (error) {
168→        console.error('get_unread_notification_count rpc error:', error.message);
169→        throw { status: 500, error: 'error fetching count in notifications table' };
170→    }
171→
172→    return { count: data ?? 0 };
173→};
174→
175→export const readNotificationService = async (userId, notifId, source) => {
176→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
177→
178→    const { error } = await supabase
179→        .from(tableName)
180→        .update({ read: true })
181→        .eq('receiver_id', userId)
182→        .eq('id', notifId);
183→
184→    if (error) {
185→        console.error('error updating notification read status:', error);
186→        throw { status: 500, error: 'error updating the notification read status' };
187→    }
188→
189→    return { message: 'notification was read!' };
190→};
191→
192→export const deleteNotificationService = async (userId, notifId, source) => {
193→    if (!notifId) {
194→        throw { status: 400, error: 'notifId is required' };
195→    }
196→
197→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
198→
199→    const { error } = await supabase
200→        .from(tableName)
201→        .delete()
202→        .eq('receiver_id', userId)
203→        .eq('id', notifId);
204→
205→    if (error) {
206→        console.error('supabase error while deleting notification:', error.message);
207→        throw { status: 500, error: 'supabase error while deleting notification' };
208→    }
209→
210→    return { message: 'success' };
211→};
212→
213→export { NOTIFICATION_LIMIT_MIN, NOTIFICATION_LIMIT_MAX, NOTIFICATION_DEFAULT_LIMIT };
