193→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
194→                        <path d="M19 12H5"/>
195→                        <path d="M12 19l-7-7 7-7"/>
196→                    </svg>
