207→                    {!isRecovery && (
208→                        <div className="settings-field">
209→                            <label htmlFor="current-password">Current Password</label>
210→                            <div className="input-with-action">
211→                                <input
212→                                    id="current-password"
213→                                    type={showCurrentPass ? 'text' : 'password'}
214→                                    value={currentPassword}
215→                                    onChange={(e) => setCurrentPassword(e.target.value)}
216→                                    placeholder="Enter current password"
217→                                    className="auth-input"
218→                                    autoComplete="current-password"
219→                                />
220→                                <button
221→                                    className="show-toggle"
222→                                    type="button"
223→                                    onClick={() => setShowCurrentPass((p) => !p)}
224→                                >
225→                                    {showCurrentPass ? 'Hide' : 'Show'}
226→                                </button>
227→                            </div>
228→                        </div>
229→                    )}
230→
231→                    <div className="settings-field">
232→                        <label htmlFor="new-password">New Password</label>
233→                        <div className="input-with-action">
234→                            <input
235→                                id="new-password"
236→                                type={showNewPass ? 'text' : 'password'}
237→                                value={newPassword}
238→                                onChange={(e) => setNewPassword(e.target.value)}
239→                                placeholder="At least 6 characters"
240→                                className="auth-input"
241→                                autoComplete="new-password"
242→                            />
243→                            <button
244→                                className="show-toggle"
245→                                type="button"
246→                                onClick={() => setShowNewPass((p) => !p)}
247→                            >
248→                                {showNewPass ? 'Hide' : 'Show'}
249→                            </button>
250→                        </div>
251→                    </div>
252→
253→                    <div className="settings-field">
254→                        <label htmlFor="confirm-password">Confirm New Password</label>
255→                        <input
256→                            id="confirm-password"
257→                            type="password"
258→                            value={confirmPassword}
259→                            onChange={(e) => setConfirmPassword(e.target.value)}
