  1→import React, { useEffect, useMemo } from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useInView } from 'react-intersection-observer';
  4→import { useAuth } from '../../../Context/useAuth';
  5→import { useMyLibrary } from '../hooks/useStoryData';
  6→import { useToggleLibrary } from '../hooks/useStoryMutations';
  7→import { motion, AnimatePresence } from 'framer-motion';
  8→import { BeatLoader } from 'react-spinners';
  9→import './StoryLibrary.css';
 10→
 11→const STATUS_LABELS = {
 12→    ongoing: 'Ongoing',
 13→    completed: 'Completed',
 14→    hiatus: 'Hiatus',
 15→};
 16→
 17→const StoryLibrary = () => {
 18→    const { session } = useAuth();
 19→    const token = session?.access_token;
 20→    const navigate = useNavigate();
 21→
 22→    const { data, fetchNextPage, hasNextPage, isFetchingNextPage, isLoading } = useMyLibrary(token);
 23→    const stories = useMemo(() => data?.pages?.flatMap(page => page.data) || [], [data]);
 24→    const toggleLibrary = useToggleLibrary(token);
 25→
 26→    const { ref: sentinelRef, inView } = useInView();
 27→    useEffect(() => {
 28→        if (inView && hasNextPage && !isFetchingNextPage) {
 29→            fetchNextPage();
 30→        }
 31→    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);
 32→
 33→    const handleRemove = (e, storyId) => {
 34→        e.stopPropagation();
 35→        toggleLibrary.mutate(storyId);
 36→    };
 37→
 38→    if (isLoading) {
 39→        return (
 40→            <div className="story-library">
 41→                <div className="story-library-loading">
 42→                    <BeatLoader size={10} color="var(--text-muted)" />
 43→                </div>
 44→            </div>
 45→        );
 46→    }
 47→
 48→    return (
 49→        <div className="story-library">
 50→            <div className="story-library-header">
 51→                <button className="story-library-back" onClick={() => navigate(-1)}>
 52→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
 53→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 54→                    </svg>
 55→                </button>
 56→                <h2 className="story-library-title">My Library</h2>
 57→            </div>
 58→
 59→            {(!isLoading && stories.length === 0) ? (
 60→                <div className="story-library-empty">
 61→                    <p>Your library is empty.</p>
 62→                    <button
 63→                        className="story-library-browse-btn"
 64→                        onClick={() => navigate('/home/stories')}
 65→                    >
 66→                        Browse Stories
 67→                    </button>
 68→                </div>
 69→            ) : (
 70→                <div className="story-library-list">
 71→                    <AnimatePresence>
 72→                        {stories.map((story) => (
 73→                            <motion.div
 74→                                key={story.id}
 75→                                className="story-library-card"
 76→                                initial={{ opacity: 0, y: 10 }}
 77→                                animate={{ opacity: 1, y: 0 }}
 78→                                exit={{ opacity: 0, y: -10 }}
 79→                                onClick={() => navigate(`/home/stories/${story.id}`)}
 80→                            >
 81→                                <div className="story-library-card-cover">
 82→                                    {story.cover_url ? (
 83→                                        <img src={story.cover_url} alt={story.title} loading="lazy" />
 84→                                    ) : (
 85→                                        <div className="story-library-card-cover-placeholder">
 86→                                            <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="var(--text-muted)">
 87→                                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 88→                                            </svg>
 89→                                        </div>
 90→                                    )}
 91→                                </div>
 92→                                <div className="story-library-card-info">
 93→                                    <h3 className="story-library-card-title">{story.title}</h3>
 94→                                    {story.users && (
 95→                                        <div className="story-library-card-author">
 96→                                            {story.users.image_url && (
 97→                                                <img src={story.users.image_url} alt="" className="story-library-card-author-avatar" />
 98→                                            )}
 99→                                            <span>{story.users.name}</span>
100→                                        </div>
101→                                    )}
102→                                    <div className="story-library-card-meta">
103→                                        <span className={`story-status-badge story-status-${story.status}`}>
104→                                            {STATUS_LABELS[story.status] || story.status}
105→                                        </span>
106→                                    </div>
107→                                    <div className="story-library-card-stats">
108→                                        <span>{story.vote_count || 0} votes</span>
109→                                        <span>{story.read_count || 0} reads</span>
110→                                    </div>
111→                                </div>
112→                                <div className="story-library-card-actions">
113→                                    <button
114→                                        className="story-library-remove-btn"
115→                                        onClick={(e) => handleRemove(e, story.id)}
116→                                        title="Remove from library"
117→                                    >
118→                                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
119→                                            <path d="M17 3H7c-1.1 0-2 .9-2 2v16l7-3 7 3V5c0-1.1-.9-2-2-2z"/>
120→                                        </svg>
121→                                    </button>
122→                                </div>
123→                            </motion.div>
124→                        ))}
125→                    </AnimatePresence>
126→                    <div ref={sentinelRef} style={{ height: 1 }} />
127→                    {isFetchingNextPage && (
128→                        <div className="story-library-loading">
129→                            <BeatLoader size={10} color="var(--text-muted)" />
130→                        </div>
131→                    )}
132→                </div>
133→            )}
134→        </div>
135→    );
136→};
137→
138→export default StoryLibrary;
