 5→const fmt = (n) => {
 6→    if (!n || n === 0) return '0';
 7→    if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
 8→    return String(n);
 9→};
10→
11→const StatTile = ({ icon, value, label, microCopy, index }) => {
12→    const animated = useAnimatedCounter(value, 900 + index * 50);
13→
14→    return (
15→        <motion.div
16→            className="recap-tile"
17→            initial={{ opacity: 0, y: 14 }}
18→            animate={{ opacity: 1, y: 0 }}
19→            transition={{ duration: 0.35, delay: 0.1 + index * 0.08, ease: 'easeOut' }}
20→        >
21→            <span className="recap-tile-icon">{icon}</span>
22→            <span className="recap-tile-value">{fmt(animated)}</span>
23→            <span className="recap-tile-label">{label}</span>
24→            {microCopy && <span className="recap-tile-micro">{microCopy}</span>}
25→        </motion.div>
26→    );
27→};
28→
29→export default StatTile;
