 2→
 3→const easeOutExpo = (t) => (t === 1 ? 1 : 1 - Math.pow(2, -10 * t));
 4→
 5→const useAnimatedCounter = (target, duration = 900) => {
 6→    const [value, setValue] = useState(0);
 7→    const rafRef = useRef(null);
 8→
 9→    useEffect(() => {
10→        if (!target || target === 0) { setValue(0); return; }
11→
12→        const start = performance.now();
13→
14→        const tick = (now) => {
15→            const elapsed = Math.min((now - start) / duration, 1);
16→            setValue(Math.round(easeOutExpo(elapsed) * target));
17→            if (elapsed < 1) rafRef.current = requestAnimationFrame(tick);
18→        };
19→
20→        rafRef.current = requestAnimationFrame(tick);
21→        return () => { if (rafRef.current) cancelAnimationFrame(rafRef.current); };
22→    }, [target, duration]);
23→
24→    return value;
25→};
26→
27→export default useAnimatedCounter;
