229→export const repostService = async(sourceJournalId, caption, userId) => {
230→    if(!sourceJournalId || !userId){
231→        throw new AppError(400, 'sourceJournalId or userId is undefined');
232→    }
233→
234→    if(caption && caption.length > 280){
235→        throw new AppError(400, 'caption must be 280 characters or less');
236→    }
237→
238→    // Fetch source journal
239→    const {data: sourceJournal, error: errorSourceJournal} = await supabase
240→        .from('journals')
241→        .select('id, title, user_id, privacy, is_repost, repost_source_journal_id')
242→        .eq('id', sourceJournalId)
243→        .maybeSingle();
244→
245→    if(errorSourceJournal){
246→        console.error('supabase error while fetching source journal:', errorSourceJournal.message);
247→        throw new AppError(500, 'supabase error while fetching source journal');
248→    }
249→
250→    if(!sourceJournal){
251→        throw new AppError(404, 'source journal not found');
252→    }
253→
254→    if(sourceJournal.privacy !== 'public'){
255→        throw new AppError(403, 'cannot repost a private post');
256→    }
257→
258→    if(sourceJournal.user_id === userId){
259→        throw new AppError(403, 'cannot repost your own post');
260→    }
261→
262→    // If reposting a repost, follow chain to the ultimate original
263→    let ultimateSourceId = sourceJournalId;
264→    let ultimateSourceUserId = sourceJournal.user_id;
265→    let ultimateSourceTitle = sourceJournal.title;
266→
267→    if(sourceJournal.is_repost && sourceJournal.repost_source_journal_id){
268→        const {data: originalJournal, error: errorOriginal} = await supabase
269→            .from('journals')
270→            .select('id, title, user_id, privacy')
271→            .eq('id', sourceJournal.repost_source_journal_id)
272→            .maybeSingle();
273→
274→        if(errorOriginal){
275→            console.error('supabase error fetching original:', errorOriginal.message);
276→            throw new AppError(500, 'supabase error while fetching original post');
277→        }
278→        if(!originalJournal){
279→            throw new AppError(404, 'original post no longer exists');
280→        }
281→        if(originalJournal.privacy !== 'public'){
282→            throw new AppError(403, 'cannot repost a private post');
283→        }
284→        if(originalJournal.user_id === userId){
285→            throw new AppError(403, 'cannot repost your own post');
286→        }
287→
288→        ultimateSourceId = originalJournal.id;
289→        ultimateSourceUserId = originalJournal.user_id;
290→        ultimateSourceTitle = originalJournal.title;
291→    }
292→
293→    // Check for duplicate repost
294→    const {data: existingRepost, error: errorExisting} = await supabase
295→        .from('journals')
296→        .select('id')
297→        .eq('user_id', userId)
298→        .eq('repost_source_journal_id', ultimateSourceId)
299→        .eq('is_repost', true)
300→        .maybeSingle();

