 74→export const submitReplyController = asyncHandler(async (req, res) => {
 75→    const { parent_id, receiver_id, post_id } = req.params;
 76→    const user_id = req.userId;
 77→    const { reply } = req.body;
 78→    const isOwner = user_id === receiver_id;
 79→
 80→    if (!parent_id || !post_id || !receiver_id) {
 81→        return res.status(400).json({ error: 'parent_id || post_id || receiver_id is missing' });
 82→    }
 83→    if (!reply || reply.length > 201 || typeof reply !== 'string') {
 84→        return res.status(400).json({ error: 'reply is not a string or maybe undefined' });
 85→    }
 86→
 87→    const insertReplyPromise = supabase
 88→        .from('comments')
 89→        .insert({ post_id, user_id, comment: reply, parent_id });
 90→
 91→    const insertNotifPromise = supabase
 92→        .from('notifications')
 93→        .insert({ sender_id: user_id, receiver_id, type: 'reply', journal_id: post_id, read: false });
 94→
 95→    const [insertNotif, insertReply] = await Promise.all([
 96→        isOwner ? Promise.resolve({ error: null }) : insertNotifPromise,
 97→        insertReplyPromise
 98→    ]);
 99→
100→    if (insertReply.error || insertNotif.error) {
101→        console.error('supabase error:', insertReply.error?.message || insertNotif.error?.message);
102→        return res.status(500).json({ error: 'supabase error' });
103→    }
104→
105→    return res.status(200).json({ message: 'success' });
