                        <g id="notification-bell">
                            <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M14.802 19.8317C15.4184 19.7699 15.8349 20.4242 15.5437 20.9539C15.3385 21.3271 15.0493 21.6529 14.7029 21.9197C14.3496 22.1918 13.9397 22.4006 13.5 22.5408C13.0601 22.6812 12.593 22.7522 12.1242 22.7522C11.6554 22.7522 11.1883 22.6812 10.7484 22.5408C10.3087 22.4006 9.89883 22.1918 9.54556 21.9197C9.1991 21.6529 8.90988 21.3271 8.70472 20.9539C8.41354 20.4242 8.83002 19.7699 9.44644 19.8317C9.63869 19.851 11.1433 19.9981 12.1242 19.9981C13.1051 19.9981 14.6097 19.851 14.802 19.8317Z" fill={pathname === '/home/notifications' ? activeColor : inactiveColor}/>
                            <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M8.52901 2.08755C10.7932 1.00445 13.4465 0.967602 15.7423 1.98737L15.9475 2.07851C18.3532 3.14707 19.8934 5.4622 19.8934 8.0096L19.8934 9.27297C19.8934 10.2885 20.1236 11.2918 20.5681 12.213L20.8335 12.7632C22.0525 15.29 20.465 18.2435 17.6156 18.7498L17.455 18.7783C13.93 19.4046 10.3154 19.4046 6.79044 18.7783C3.90274 18.2653 2.37502 15.1943 3.77239 12.7115L3.99943 12.3082C4.55987 11.3124 4.85335 10.1981 4.85335 9.06596L4.85335 7.79233C4.85335 5.3744 6.27704 3.16478 8.52901 2.08755Z" fill={pathname === '/home/notifications' ? activeColor : inactiveColor}/>
                        </g>
                    </g>
                </svg>
            },
            {
                path: '/home/bookmark',
                label: 'Bookmarks',
                action: ()=> navigatePath('/home/bookmark'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="none">
                    <g id="style=fill">
                        <g id="bookmark">
                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={pathname === '/home/bookmark' ? activeColor : inactiveColor}/>
                        </g>
                    </g>
                </svg>
            },
            {
                path: '/home/settings',
                label: 'Settings',
                action: () => navigatePath('/home/settings'),
                icon:
                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={pathname === '/home/settings' ? "#5f92ff" : "#b6b6b6"}>
                    <path d="M12 15.5A3.5 3.5 0 1 0 12 8.5a3.5 3.5 0 0 0 0 7Z"/>
                    <path d="M19.43 12.98c.04-.32.07-.64.07-.98 0-.34-.03-.66-.07-.98l2.11-1.65a.5.5 0 0 0 .12-.64l-2-3.46a.5.5 0 0 0-.61-.22l-2.49 1a7.04 7.04 0 0 0-1.69-.98l-.38-2.65A.49.49 0 0 0 14 2h-4a.49.49 0 0 0-.49.42l-.38 2.65c-.61.25-1.17.59-1.69.98l-2.49-1a.5.5 0 0 0-.61.22l-2 3.46a.49.49 0 0 0 .12.64l2.11 1.65c-.04.32-.07.65-.07.98 0 .33.03.66.07.98l-2.11 1.65a.5.5 0 0 0-.12.64l2 3.46c.12.22.39.3.61.22l2.49-1c.52.4 1.08.73 1.69.98l.38 2.65c.05.24.26.42.49.42h4c.24 0 .44-.18.49-.42l.38-2.65c.61-.25 1.17-.59 1.69-.98l2.49 1c.23.09.49 0 .61-.22l2-3.46a.5.5 0 0 0-.12-.64l-2.11-1.65Z"/>
                </svg>
            },
            {
                label: 'Write', action: () => handleOpenTextEditor(),
                className: 'write-journal-bttn'
            },
        ];
    }, [location.pathname, isGuest, notifCount, navigate, navigatePath, handleOpenTextEditor]);

    const handleOnboardingComplete = useCallback((action) => {
        setShowOnboarding(false);
        queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
        if (action === 'write') {
            handleOpenTextEditor();
        } else if (action === 'story') {
            navigate('/home/stories/new');
        }
        // 'explore' → just close, user lands on feed
    }, [queryClient, session, handleOpenTextEditor, navigate]);

    const handleClickMobileProfileLink = () =>{
        setShowMobileSideBar(true)
    }
    const handleClickCloseSidebar = () =>{
        setShowMobileSideBar(false)
    }

    const handleOpenOpinionTextEditor = () =>{
        setShowOpinionEditor(true)
    }
    const handleCloseOpiniionTextEditor = () =>{
        setShowOpinionEditor(false);
    }

    useEffect(() => {
        const launchState = location.state;
        if(!launchState?.openEditor){
            return;
        }

        handleOpenTextEditor({
            initialTitle: launchState?.initialTitle || ''
        });

        navigate(location.pathname, {replace: true, state: null});
    }, [location.state, location.pathname, navigate, handleOpenTextEditor]);

    //handle show links header when stop scrolling and hides header when scrolling
    // useEffect(() =>{
    //     const handleScroll = (e) => {
    //         clearTimeout(scrollRefTimeOut.current)
    //         setShowHeaders(false)

    //         scrollRefTimeOut.current = setTimeout(() => {
    //             setShowHeaders(true)
    //         }, 500);
    //     }

    //     document.addEventListener('scroll', handleScroll, true);

    //     return() => {
    //         document.removeEventListener('scroll', handleScroll, true);
    //         clearTimeout(scrollRefTimeOut.current)
    //     }
    // }, [])

    useEffect(() => {
        if(session && !loading && user){
            const profileData = user?.userData?.[0];
            const exists = !!profileData;
            const onboarded = profileData?.onboarding_completed ?? true;
            if(!exists || !onboarded){
                setOnboardingUserExists(exists);
                setShowOnboarding(true);
            }
        }
    },[session, loading, user])



    if(isLoading && !isGuest){
        return(
            <Loader/>
        )
    }

    return(
        <>
        {!isGuest && showOnboarding && (
            <OnboardingWizard
                onComplete={handleOnboardingComplete}
                userExists={onboardingUserExists}
            />
        )}

        <AnimatePresence>
        {!isGuest && showEditor && (
            <Editor
                key={'main-editor'}
                onClose={handleCloseEditor}
                initialTitle={editorLaunchConfig.initialTitle}
                promptId={editorLaunchConfig.promptId}
                promptText={editorLaunchConfig.promptText}
            />
        )}

        {!isGuest && showOpinionEditor && (
            <OpinionEditor onClose={handleCloseOpiniionTextEditor}/>
        )}

        </AnimatePresence>

        <div className="home-parent-container">
             <div className="side-bar-holder-container">
                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
            </div>
            <div className="center-bar-holder-container">

                {/* <AnimatePresence>
                {showHeaders && (
                    <motion.div 
                    className="newsfeed-header"
                    initial={{opacity: 0}}
                    animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
                    exit={{ opacity: 0, y: -20,
                        transition: { 
                            duration: 0.2,
                            ease: "easeOut"
                        }
                    }}
                    >
                        {header_links.map((header_link, index) => (
                            <div key={index} className="header-links">
                                {header_link.label}
                            </div>
                        ))}
                    </motion.div>
                )}
                </AnimatePresence> */}

                <Outlet context={{ clickOpenSidebar: handleClickMobileProfileLink, handleOpenTextEditor }} />
            </div>
            <div className="sidebar-right-holder-container">
                {/* Log out */}
                {!isMobile && !isOpinionsViewer &&(
                    <SidebarOpinions openEditor={handleOpenOpinionTextEditor}/>
                )}

            </div>

            {!isGuest && !isOpinionsPage && !isOpinionsViewer && (
                <WriteJournalButton onOpen={handleOpenTextEditor} hideOnHomeFeed={location.pathname === '/home' || location.pathname === '/home/opinions'}/>
            )}

            <MobileNavlink />
        </div>

        {showMobileSideBar && (
            <MobileSidebarLink onclose={handleClickCloseSidebar}/>
        )}
        </>
    )
}
export default HomePage

