 1→/**
 2→ * Wraps an async route/controller handler with error handling.
 3→ * The wrapped function receives (req, res) and should return or throw.
 4→ * On error, reads error.status and error.error || error.message.
 5→ */
 6→export const asyncHandler = (fn) => async (req, res, next) => {
 7→    try {
 8→        await fn(req, res, next);
 9→    } catch (error) {
10→        const status = error?.status || 500;
11→        const message = error?.error || error?.message || 'internal server error';
12→        console.error(`[${req.method} ${req.originalUrl}]`, error);
13→        return res.status(status).json({ error: message });
14→    }
15→};
16→

1→export class AppError extends Error {
2→    constructor(status, message) {
3→        super(message);
4→        this.status = status;
5→        this.error = message;
6→        this.name = 'AppError';
7→    }
